Imports a list of domains from an Amazon S3 file into a firewall domain list. The file
should contain one domain per line.

!!! important
    Route 53 Global Resolver is a global service that supports resolvers in multiple Amazon
    Web Services Regions but you must specify the US East (Ohio) Region to create, update,
    or otherwise work with Route 53 Global Resolver resources. That is, for example, specify
    `--region us-east-2` on Amazon Web Services CLI commands.

# Arguments

- `domain_file_url`: The fully qualified URL of the file in Amazon S3 that contains the list
  of domains to import. The file should contain one domain per line.
- `firewall_domain_list_id`: ID of the DNS Firewall domain list that you want to import the
  domain list to.
- `operation`: This value is `REPLACE`, and it updates the domain list to match the list of
  domains in the imported file.
"""
function import_firewall_domains end

function import_firewall_domains(
    domainFileUrl,
    firewallDomainListId,
    operation;
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return route53globalresolver(
        "PATCH",
        "/firewall-domain-lists/$(firewallDomainListId)/domains/s3_file_url",
        Dict{String,Any}("domainFileUrl" => domainFileUrl, "operation" => operation);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function import_firewall_domains(
    domainFileUrl,
    firewallDomainListId,
    operation,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return route53globalresolver(
        "PATCH",
        "/firewall-domain-lists/$(firewallDomainListId)/domains/s3_file_url",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "domainFileUrl" => domainFileUrl, "operation" => operation
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

